const query = $input.item.json.query || $input.item.json.input || '';
const queryLower = query.toLowerCase();

const articles = [
  { id: 'KB001', title: 'Product Return Policy', content: 'Items can be returned within 30 days. Contact support for a return label.' },
  { id: 'KB002', title: 'Troubleshooting Common Issues', content: 'Try restarting the device. If issue persists, perform a factory reset via Settings > Reset.' },
  { id: 'KB003', title: 'Billing and Refund FAQ', content: 'Refunds are processed within 5-7 business days. Check email for confirmation.' },
  { id: 'KB004', title: 'Shipping Delays', content: 'Current shipping times are 5-10 business days. Expedited shipping available.' },
  { id: 'KB005', title: 'Account Security', content: 'Enable two-factor auth in Settings > Security. Contact support if you suspect unauthorized access.' },
  { id: 'KB006', title: 'Product Setup Guide', content: 'Follow the quick start guide. Video tutorials at support.example.com/setup.' },
];

const matches = articles.filter(a =>
  queryLower.split(' ').some(word => word.length > 3 && (a.title.toLowerCase().includes(word) || a.content.toLowerCase().includes(word)))
);

const result = matches.length > 0
  ? matches.map(a => `[${a.id}] ${a.title}: ${a.content}`).join('\n')
  : 'No matching articles found.';

return [{ json: { response: result } }];

const input = $input.item.json;
const customerMessage = input.customer_message || input.input || 'No message';
const priority = (input.priority || 'MEDIUM').toUpperCase();
const sentiment = (input.sentiment || 'NEUTRAL').toUpperCase();

const ticketId = 'TKT-' + Date.now().toString(36).toUpperCase();
const assignmentMap = { 'HIGH': 'Senior Support Team', 'MEDIUM': 'General Support', 'LOW': 'Auto-Response Queue' };
const slaMap = { 'HIGH': '4 hours', 'MEDIUM': '24 hours', 'LOW': '48 hours' };
const draftTemplates = {
  'NEGATIVE': 'We sincerely apologize. A support specialist will follow up within 24 hours.',
  'POSITIVE': 'Thank you for your kind feedback! We are thrilled you enjoy the product.',
  'NEUTRAL': 'Thank you for reaching out. We want to ensure you have the best experience.',
};

const ticket = {
  ticket_id: ticketId,
  priority,
  sentiment,
  customer_message: customerMessage.substring(0, 200),
  assigned_to: assignmentMap[priority] || 'General Support',
  sla: slaMap[priority] || '24 hours',
  draft_response: draftTemplates[sentiment] || draftTemplates['NEUTRAL'],
  status: 'OPEN',
  created_at: new Date().toISOString(),
};

return [{ json: { response: JSON.stringify(ticket) } }];
